form:Form.form:Scripts:
		function onChangeClase()
{     
	if (Ctrl("oi_clase_org").GetXValue()=="")
	{
		Ctrl('treeESTR').loadFromString("<tree/>");
		Ctrl('treeESTR').SetXValue("");
	}

	var mp, nSQL, txtTree;

	np = new NomadProxy("", ut);
	nSQL = np.SQLService();

  txtTree = nSQL.Get(Ctrl("main").getResource("qry:ESTRUCTURA"), "<PARAM oi_clase_org=\""+Ctrl("oi_clase_org").GetXValue()+"\" estructura=\""+Ctrl("estructura").GetXValue()+ "\" id=\""+Ctrl("treeESTR").GetXValue()+"\" />");
	Ctrl('treeESTR').loadFromString(txtTree);
	Ctrl('treeESTR').SetXValue("");
}

function VALESTR()
{
  if (Ctrl('treeESTR').GetXValue() == "0")
  {
  	alert("Debe elegir una Posición");
  	return false;
  }             
  return true;  
}
